// Validate the extracted invoice data
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let extractedData;

    // Parse AI output if it's a string
    if (typeof item.json.output === 'string') {
      extractedData = JSON.parse(item.json.output);
    } else {
      extractedData = item.json.output || item.json;
    }

    // Required fields for validation
    const requiredFields = ['invoice_number', 'invoice_date', 'vendor_name', 'total_amount'];
    const missingFields = [];

    // Check for required fields
    for (const field of requiredFields) {
      if (!extractedData[field] || extractedData[field] === null) {
        missingFields.push(field);
      }
    }

    // Validate date format
    const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
    if (extractedData.invoice_date && !dateRegex.test(extractedData.invoice_date)) {
      missingFields.push('invalid_date_format');
    }

    // Validate total amount is a number
    if (extractedData.total_amount && isNaN(parseFloat(extractedData.total_amount))) {
      missingFields.push('invalid_total_amount');
    }

    // Determine validation status
    const isValid = missingFields.length === 0;
    const confidenceLevel = extractedData.extraction_confidence || 'unknown';

    // Get original filename from the previous nodes in the chain
    let originalFileName = 'unknown';
    try {
      // Try to get filename from Monitor Invoice Folder node
      const monitorNode = $node['Monitor Invoice Folder'];
      if (monitorNode && monitorNode.first() && monitorNode.first().json) {
        originalFileName = monitorNode.first().json.name || monitorNode.first().json.originalFilename || 'unknown';
      }

      // Alternative: try to get from Extract from File node
      const extractNode = $node['Extract from File'];
      if (extractNode && extractNode.first() && extractNode.first().json) {
        originalFileName = extractNode.first().json.fileName || originalFileName;
      }
    } catch (nodeError) {
      console.log('Could not retrieve original filename:', nodeError.message);
    }

    results.push({
      json: {
        ...extractedData,
        validation_status: isValid ? 'valid' : 'invalid',
        validation_errors: missingFields,
        confidence_level: confidenceLevel,
        requires_manual_review: !isValid || confidenceLevel === 'low',
        processed_at: new Date().toISOString(),
        original_file: originalFileName
      }
    });

  } catch (error) {
    // Get original filename safely even in error cases
    let originalFileName = 'unknown';
    try {
      const monitorNode = $node['Monitor Invoice Folder'];
      if (monitorNode && monitorNode.first() && monitorNode.first().json) {
        originalFileName = monitorNode.first().json.name || monitorNode.first().json.originalFilename || 'unknown';
      }
    } catch (nodeError) {
      console.log('Could not retrieve original filename in error case:', nodeError.message);
    }

    results.push({
      json: {
        validation_status: 'error',
        error_message: error.message,
        validation_errors: ['parsing_error'],
        requires_manual_review: true,
        processed_at: new Date().toISOString(),
        original_file: originalFileName
      }
    });
  }
}

return results;

